const firstRowsFrom = (names) => {
  for (const name of names) {
    try {
      const rows = $items(name, 0, 0).map((i) => i.json || {});
      if (rows.length > 0) return rows;
    } catch (_e) {}
  }
  return [];
};

const firstRowFrom = (names) => {
  const rows = firstRowsFrom(names);
  return rows.length > 0 ? rows[0] : {};
};

const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[̀-ͯ]/g, '')
  .toLowerCase();
const uniq = (arr) => [...new Set((Array.isArray(arr) ? arr : []).map((x) => toStr(x)).filter(Boolean))];

const input = $json || {};
const ctx = firstRowFrom(['Finalize Analysis Context']);

const analysisId = toNum(
  input.analysis_id ??
  input.impact_analysis_id ??
  ctx.impact_analysis_id ??
  ctx.analysis_id
);
if (!analysisId) {
  throw new Error('[Build Review Context] analysis_id/impact_analysis_id ausente.');
}

const actionRaw = norm(input.acao || input.action || 'ask');
const action = actionRaw === 'request_fix' ? 'request_fix' : 'ask';

const question = toStr(input.pergunta || input.question || input.ask || input.prompt);
if (!question) {
  throw new Error('[Build Review Context] pergunta obrigatoria (pergunta/question).');
}

const repoFilter = norm(input.repo || input.repo_name || input.target_repo || '');
const changeIdFilter = toNum(input.change_id);

const analysisCandidates = [
  firstRowFrom(['Finalize Analysis Context']),
  firstRowFrom(['Parse LLM JSON']),
  firstRowFrom(['Parse LLM JSON1']),
  firstRowFrom(['Parse LLM JSON2']),
  firstRowFrom(['Insert Impact Analysis']),
  firstRowFrom(['Insert Impact Analysis1']),
  firstRowFrom(['Insert Impact Analysis2'])
].filter((x) => x && Object.keys(x).length > 0);

let analysisRow = analysisCandidates.find((r) => toNum(r.impact_analysis_id || r.analysis_id || r.id) === analysisId);
if (!analysisRow) analysisRow = analysisCandidates[0] || {};

const analysis = (analysisRow.analysis && typeof analysisRow.analysis === 'object')
  ? analysisRow.analysis
  : ((analysisRow.analysis_raw && typeof analysisRow.analysis_raw === 'object') ? analysisRow.analysis_raw : {});

const llmRawText = toStr(analysisRow.llm_raw_text || analysisRow.raw_text || '');

const changeSourceNames = [
  'Upsert Code Changes',
  'Build Code Change Rows',
  'Build Change Rows',
  'Parse Code Changes JSON',
  'Parse Code Changes Json',
  'Parse Code Changes JSON1',
  'Parse Code Changes JSON2',
  'Insert Code Changes',
  'Create Governance PR (GitHub API)',
  'Create Governance PR (GitHub API)1'
];

const rawChangeRows = changeSourceNames.flatMap((name) => firstRowsFrom([name]));
if (rawChangeRows.length === 0) {
  throw new Error('[Build Review Context] nenhum registro de change encontrado nos nodes de origem.');
}

const normalizedChanges = [];
for (const row of rawChangeRows) {
  const rowAnalysisId = toNum(row.impact_analysis_id || row.analysis_id || analysisId);
  if (rowAnalysisId !== analysisId) continue;

  const id = toNum(row.change_id || row.id);
  const repo = toStr(row.repo_name || row.repo || row.target_repo || row.repositorio || '');
  const summary = toStr(row.change_summary || row.summary || row.descricao || row.description);

  const codeBlocks = [];
  if (toStr(row.code)) codeBlocks.push(toStr(row.code));

  const arrays = [row.code_changes, row.suggested_code_changes, row.snippets];
  for (const arr of arrays) {
    if (Array.isArray(arr)) {
      for (const item of arr) {
        const text = toStr(item);
        if (text) codeBlocks.push(text);
      }
    }
  }

  if (!id && !summary && codeBlocks.length === 0) continue;

  normalizedChanges.push({
    change_id: id,
    repo_name: repo,
    summary,
    code_blocks: uniq(codeBlocks)
  });
}

if (normalizedChanges.length === 0) {
  throw new Error('[Build Review Context] nenhum change encontrado para analysis_id=' + analysisId);
}

const filtered = normalizedChanges.filter((c) => {
  if (repoFilter && norm(c.repo_name) !== repoFilter) return false;
  if (changeIdFilter && c.change_id !== changeIdFilter) return false;
  return true;
});

if (filtered.length === 0) {
  throw new Error('[Build Review Context] filtros retornaram 0 resultados. analysis_id=' + analysisId + ', repo=' + repoFilter + ', change_id=' + (changeIdFilter ?? 'null'));
}

const testRows = [
  ...firstRowsFrom(['Build Tests For Testsuite Rows (LLM)']),
  ...firstRowsFrom(['Build Tests For Testsuite Rows (LLM)1']),
  ...firstRowsFrom(['Build Tests For Testsuite Rows (LLM)2']),
  ...firstRowsFrom(['Upsert Tests For Testsuite (LLM)']),
  ...firstRowsFrom(['Upsert Tests For Testsuite (LLM)1']),
  ...firstRowsFrom(['Upsert Tests For Testsuite (LLM)2'])
]
  .map((r) => r || {})
  .filter((r) => {
    const rid = toNum(r.impact_analysis_id || r.analysis_id || analysisId);
    return rid === analysisId;
  })
  .map((r) => ({
    change_id: toNum(r.change_id),
    testsuite_id: toNum(r.testsuite_id),
    description: toStr(r.description || r.test_description || r.test || r.step)
  }))
  .filter((r) => r.description);

const maxCharsPerCode = toNum(input.max_chars_per_code) || 3000;
const maxContextChars = toNum(input.max_context_chars) || 60000;

const compactChanges = filtered.map((c) => ({
  change_id: c.change_id,
  repo_name: c.repo_name,
  summary: c.summary,
  code_blocks: c.code_blocks.map((b) => b.slice(0, maxCharsPerCode))
}));

const compactTests = testRows.slice(0, 200);

const payload = {
  analysis_id: analysisId,
  action,
  question,
  filters: {
    repo: repoFilter || null,
    change_id: changeIdFilter || null
  },
  analysis_resumo: toStr(analysis.resumo || analysis.summary || ''),
  analysis_viabilidade: analysis.viabilidade || null,
  changes: compactChanges,
  tests: compactTests,
  llm_raw_text: llmRawText ? llmRawText.slice(0, 8000) : ''
};

const reviewContextText = JSON.stringify(payload, null, 2).slice(0, maxContextChars);

return [{
  json: {
    analysis_id: analysisId,
    action,
    question,
    review_context_text: reviewContextText,
    review_context_stats: {
      changes: compactChanges.length,
      tests: compactTests.length,
      context_chars: reviewContextText.length,
      has_llm_raw_text: !!llmRawText
    },
    anthropic_api_key: toStr(input.anthropic_api_key),
    llm_model: toStr(input.llm_model || 'claude-sonnet-4-5-20250929'),
    max_tokens: toNum(input.max_tokens) || 1400
  }
}];

const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const extractText = (resp) => {
  const blocks = Array.isArray(resp?.content) ? resp.content : [];
  const textParts = blocks
    .filter((b) => b && b.type === 'text' && typeof b.text === 'string')
    .map((b) => b.text.trim())
    .filter(Boolean);
  return textParts.join('
').trim();
};

const tryParseJson = (raw) => {
  try {
    return JSON.parse(raw);
  } catch (_e) {}

  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const cut = raw.slice(start, end + 1);
    try {
      return JSON.parse(cut);
    } catch (_e) {}
  }
  return null;
};

const input = $json || {};
const analysisId = toNum(input.analysis_id);
if (!analysisId) throw new Error('[Answer Or Request Fix] analysis_id ausente.');

const action = toStr(input.action || 'ask');
const question = toStr(input.question);
const contextText = toStr(input.review_context_text);
if (!question) throw new Error('[Answer Or Request Fix] question/pergunta ausente.');
if (!contextText) throw new Error('[Answer Or Request Fix] review_context_text ausente.');

const envKey = (typeof process !== 'undefined' && process.env && process.env.ANTHROPIC_API_KEY)
  ? String(process.env.ANTHROPIC_API_KEY).trim()
  : '';
const apiKey = toStr(input.anthropic_api_key || envKey);
if (!apiKey) {
  throw new Error('[Answer Or Request Fix] ANTHROPIC_API_KEY ausente. Informe em input.anthropic_api_key ou variavel de ambiente.');
}

const model = toStr(input.llm_model || 'claude-sonnet-4-5-20250929');
const maxTokens = toNum(input.max_tokens) || 1400;

const systemPrompt = [
  'Voce e um revisor tecnico estrito para changes e code_changes do FastRoute.',
  'Responda SOMENTE com JSON valido, sem markdown.',
  'Baseie-se exclusivamente no contexto recebido.',
  'Se faltar evidencia, escreva explicitamente no campo resposta.',
  'Formato obrigatorio:',
  '{',
  '  "tipo": "ask|request_fix",',
  '  "resposta": "string",',
  '  "evidencias": ["string"],',
  '  "correcao_sugerida": {',
  '    "change_id": number|null,',
  '    "motivo": "string",',
  '    "novo_codigo": "string"',
  '  }',
  '}',
  'Regra: quando tipo=request_fix, correcao_sugerida deve vir preenchida.'
].join('
');

const userPrompt = [
  'Pergunta do usuario:',
  question,
  '',
  'Acao solicitada:',
  action,
  '',
  'Contexto tecnico (JSON):',
  contextText
].join('
');

let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model,
      max_tokens: maxTokens,
      temperature: 0,
      system: systemPrompt,
      messages: [
        {
          role: 'user',
          content: userPrompt
        }
      ]
    },
    json: true
  });
} catch (e) {
  const errBody = e?.response?.body ? JSON.stringify(e.response.body) : String(e?.message || e);
  throw new Error('[Answer Or Request Fix] chamada Anthropic falhou: ' + errBody);
}

const rawText = extractText(resp);
if (!rawText) {
  throw new Error('[Answer Or Request Fix] resposta vazia da Anthropic.');
}

const parsed = tryParseJson(rawText);
if (!parsed || typeof parsed !== 'object') {
  throw new Error('[Answer Or Request Fix] modelo nao retornou JSON valido. raw=' + rawText.slice(0, 1000));
}

const tipo = toStr(parsed.tipo || action || 'ask');
const resposta = toStr(parsed.resposta);
const evidencias = Array.isArray(parsed.evidencias)
  ? parsed.evidencias.map((x) => toStr(x)).filter(Boolean)
  : [];
const correcao = (parsed.correcao_sugerida && typeof parsed.correcao_sugerida === 'object')
  ? parsed.correcao_sugerida
  : null;

if (!resposta) {
  throw new Error('[Answer Or Request Fix] JSON retornado sem campo resposta.');
}

if (tipo === 'request_fix') {
  const okFix = correcao && toStr(correcao.motivo) && toStr(correcao.novo_codigo);
  if (!okFix) {
    throw new Error('[Answer Or Request Fix] request_fix sem correcao_sugerida completa.');
  }
}

return [{
  json: {
    analysis_id: analysisId,
    action: tipo,
    question,
    resposta,
    evidencias,
    correcao_sugerida: correcao,
    llm_model: model,
    llm_usage: resp?.usage || null,
    llm_stop_reason: toStr(resp?.stop_reason || ''),
    llm_raw_text: rawText,
    generated_at: new Date().toISOString()
  }
}];
